const memoryId = $('Merge All Extractions').item.json.memory_id;
const theme = $('Merge All Extractions').item.json.theme || {};

// Skip if no theme data
if (!theme.main_theme) {
  return [{ json: { _skip: true, memory_id: memoryId } }];
}

return [{
  json: {
    memory_id: memoryId,
    main_theme: theme.main_theme,
    sub_themes: JSON.stringify(theme.sub_themes || []),
    conversation_type: theme.conversation_type,
    business_relevance: theme.business_relevance,
    contains_decisions: theme.contains_decisions || false,
    contains_customer_insights: theme.contains_customer_insights || false,
    contains_personal_breakthrough: theme.contains_personal_breakthrough || false,
    contains_action_items: theme.contains_action_items || false,
    key_takeaways: JSON.stringify(theme.key_takeaways || [])
  }
}];

// Get memory_id - try all possible entry-point nodes
let memoryId, title;

try {
  memoryId = $('Create a row').first().json.id;
} catch (e) {
  try {
    memoryId = $('Store Base Memory').first().json.id;
  } catch (e2) {
    try {
      memoryId = $('Update Memory To Extracting').first().json.id;
    } catch (e3) {
      throw new Error('Could not find memory ID node');
    }
  }
}

try {
  title = $('Webhook').first().json.body.title;
} catch (e) {
  try {
    title = $('Webhook Pending').first().json.body.title || 'Untitled';
  } catch (e2) {
    title = 'Untitled';
  }
}

// Process merged LLM outputs
let entities = [], decisions = [], insights = [], reflections = [];
let strategic = [], tasks = [], theme = {};

for (const item of $input.all()) {
  try {
    let textData = null;

    // Your structure: { output: [{ content: [{ text: {...} }] }] }
    if (item.json.output?.[0]?.content?.[0]?.text) {
      textData = item.json.output[0].content[0].text;
    }

    if (!textData) continue;

    // Route based on what keys exist
    if (textData.entities) entities = textData.entities;
    if (textData.decisions) decisions = textData.decisions;
    if (textData.reflections) reflections = textData.reflections;
    if (textData.tasks) tasks = textData.tasks;
    if (textData.main_theme) theme = textData;
    if (textData.insights?.length > 0) {
      // Distinguish customer insights from strategic insights
      if (textData.insights[0].customer_name !== undefined) {
        insights = textData.insights;
      } else {
        strategic = textData.insights;
      }
    }
  } catch (e) {
    console.log('Parse error:', e.message);
  }
}

return [{
  json: { memory_id: memoryId, title, entities, decisions, insights, reflections, strategic, tasks, theme }
}];

// Look back specifically to the node that actually has the entities array
const extractionNode = $('Merge All Extractions').first().json;
const memoryId = extractionNode.memory_id;
const entities = extractionNode.entities || [];

if (entities.length === 0) {
  return [{ json: { _skip: true, memory_id: memoryId } }];
}

return entities.map(e => ({
  json: {
    memory_id: memoryId,
    entity_type: e.entity_type,
    entity_name: e.entity_name,
    context: e.context
  }
}));

const memoryId = $('Merge All Extractions').item.json.memory_id;
const decisions = $('Merge All Extractions').item.json.decisions || [];

if (decisions.length === 0) {
  return [{ json: { _skip: true, memory_id: memoryId } }];
}

return decisions.map(d => {
  const days = d.suggested_review_days || 14;
  const reviewAfter = new Date(Date.now() + days * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
  return {
    json: {
      memory_id: memoryId,
      decision: d.decision,
      category: d.category,
      reasoning: d.reasoning,
      alternatives_considered: JSON.stringify(d.alternatives_considered || []),
      confidence_level: d.confidence_level,
      emotional_context: d.emotional_context,
      review_after: reviewAfter
    }
  };
});

const memoryId = $('Merge All Extractions').item.json.memory_id;
const insights = $('Merge All Extractions').item.json.insights || [];

if (insights.length === 0) {
  return [{ json: { _skip: true, memory_id: memoryId } }];
}

return insights.map(i => ({
  json: {
    memory_id: memoryId,
    customer_name: i.customer_name,
    customer_type: i.customer_type,
    pain_point: i.pain_point,
    desire: i.desire,
    objection: i.objection,
    automation_opportunity: i.automation_opportunity,
    quote: i.quote
  }
}));

const memoryId = $('Merge All Extractions').item.json.memory_id;
const reflections = $('Merge All Extractions').item.json.reflections || [];

if (reflections.length === 0) {
  return [{ json: { _skip: true, memory_id: memoryId } }];
}

return reflections.map(r => ({
  json: {
    memory_id: memoryId,
    reflection_type: r.reflection_type,
    reflection: r.reflection,
    topic: r.topic,
    emotional_tone: r.emotional_tone
  }
}));

const memoryId = $('Merge All Extractions').item.json.memory_id;
const strategic = $('Merge All Extractions').item.json.strategic || [];

if (strategic.length === 0) {
  return [{ json: { _skip: true, memory_id: memoryId } }];
}

return strategic.map(s => ({
  json: {
    memory_id: memoryId,
    insight_category: s.insight_category,
    insight: s.insight,
    supporting_evidence: JSON.stringify(s.supporting_evidence || []),
    confidence: s.confidence,
    importance: s.importance || null,
    actionable: s.actionable,
    suggested_action: s.suggested_action
  }
}));

const memoryId = $('Merge All Extractions').item.json.memory_id;
const tasks = $('Merge All Extractions').item.json.tasks || [];

if (tasks.length === 0) {
  return [{ json: { _skip: true, memory_id: memoryId } }];
}

return tasks.map(t => ({
  json: {
    memory_id: memoryId,
    task: t.task,
    context: t.context,
    urgency: t.urgency,
    priority: t.priority,
    category: t.category,
    due_date: t.due_date || null,
    entity_name: t.entity_name || null
  }
}));

// Build a rich, searchable summary from the theme extraction
const data = $json;
const theme = data.theme || {};

const searchableParts = [
  // Main theme
  theme.main_theme,

  // Sub themes as a sentence
  theme.sub_themes?.length ? `Topics: ${theme.sub_themes.join(', ')}` : null,

  // Key takeaways
  theme.key_takeaways?.length ? `Key takeaways: ${theme.key_takeaways.join('. ')}` : null,

  // Conversation metadata
  theme.conversation_type ? `Type: ${theme.conversation_type}` : null,
  theme.business_relevance ? `Relevance: ${theme.business_relevance}` : null
];

const textToEmbed = searchableParts.filter(Boolean).join('\n\n');

return [{
  json: {
    ...data,
    text_for_embedding: textToEmbed
  }
}];
